use std::cmp::Ordering;

fn main() {
    let mut buf = String::new();
    std::io::stdin().read_line(&mut buf).unwrap();
    let (n, k) = {
        let temp: Vec<u64> = buf
            .trim()
            .split_whitespace()
            .map(|a| a.parse().unwrap())
            .collect();
        (temp[0], temp[1])
    };

    let (mut index, mut jump) = (n / 2, n / 2);
    loop {
        let sum_n = index * (index + 1) / 2;
        let eaten = n - index;

        if eaten > sum_n {
            jump = 1.max(jump / 2);
            index += jump;
            continue;
        }

        match k.cmp(&(sum_n - eaten)) {
            Ordering::Equal => break,
            Ordering::Greater => {
                jump = 1.max(jump / 2);
                index += jump;
            }
            Ordering::Less => {
                jump = 1.max(jump / 2);
                index -= jump;
            }
        }
    }

    println!("{}", n - index);
}
